import { test, expect, APIRequestContext } from '@playwright/test';

const BASE_URL = process.env.BASE_URL ?? 'http://localhost:3000';

/**
 * Helper function to make health check request
 */
async function getHealthStatus(request: APIRequestContext) {
  return await request.get(`${BASE_URL}/api/health`);
}

/**
 * Helper function for concurrent health check requests
 */
async function makeConcurrentRequests(request: APIRequestContext, count: number) {
  const requests = Array.from({ length: count }, () => 
    request.get(`${BASE_URL}/api/health`)
  );
  return await Promise.all(requests);
}

