      expect(body.ollama).toBe(firstBody.ollama);
      expect(body.chromadb).toBe(firstBody.chromadb);
      expect(body.llm_model).toBe(firstBody.llm_model);
    }

    // Verify no connection pool exhaustion (all requests completed)
    expect(bodies.length).toBe(concurrentRequests);
  });

  // SCENARIO_ID: ff92309c-c26c-4608-8eca-475a9e861519
  test('Health check with Ollama returning non-200 status', async ({ request }) => {
    // Preconditions:
